export const divide = (a: number, b: number): number => {
  if (b === 0) throw new Error('division by zero')
  return a / b
}

import { describe, it, expect } from 'vitest'
import { divide } from './divide'

describe('divide', () => {
  it('divides two numbers', () => { expect(divide(6, 3)).toBe(2) })
  it('throws on zero', () => { expect(() => divide(1, 0)).toThrow('division by zero') })
})

import { describe, it, expect } from 'vitest'
import { multiply } from './multiply'

describe('multiply', () => {
  it('multiplies two numbers', () => { expect(multiply(2, 3)).toBe(6) })
  it('handles zero', () => { expect(multiply(0, 5)).toBe(0) })
})

